<div class="page-title"><h2>Balance general</h2></div><div class="card"><form method="get" action="/reports/balance-sheet" class="form inline-form"><label>Desde<input type="date" name="from" value="<?= e($from) ?>"></label><label>Hasta<input type="date" name="to" value="<?= e($to) ?>"></label><button class="btn">Consultar</button></form></div><div class="grid three"><div class="card"><h3>Activos</h3><?php foreach($balance['assets'] as $row): ?><p><?= e($row['name']) ?> <strong class="float-right"><?= money($row['amount']) ?></strong></p><?php endforeach; ?></div><div class="card"><h3>Pasivos</h3><?php foreach($balance['liabilities'] as $row): ?><p><?= e($row['name']) ?> <strong class="float-right"><?= money($row['amount']) ?></strong></p><?php endforeach; ?></div><div class="card"><h3>Patrimonio</h3><?php foreach($balance['equity'] as $row): ?><p><?= e($row['name']) ?> <strong class="float-right"><?= money($row['amount']) ?></strong></p><?php endforeach; ?></div></div>
